        businesses = json.load(f)
else:
    businesses = data

# Regex to extract state
# Looking for ", XX, this" pattern
state_pattern = re.compile(r",\s([A-Z]{2}),\s+this")

state_reviews = {}
business_ids_in_states = {}

for b in businesses:
    desc = b.get('description', '')
    match = state_pattern.search(desc)
    if match:
        state = match.group(1)
        try:
            rc = int(b.get('review_count', 0))
        except ValueError:
            rc = 0

        state_reviews[state] = state_reviews.get(state, 0) + rc

        if state not in business_ids_in_states:
